[
  {
    "file": "source/common/http/header_utility.cc",
    "line": 43,
    "severity": "critical",
    "description": "Inverted logic in matchHeaders function. The logic now returns false when ANY header MATCHES the configuration, but it should return false when ANY header DOESN'T MATCH. This causes fault filter and RBAC to incorrectly identify requests that should be matched. The negation operator was removed from the condition, inverting the entire matching logic.",
    "fix_patch": "--- a/source/common/http/header_utility.cc
+++ b/source/common/http/header_utility.cc
@@ -40,7 +40,7 @@ bool HeaderUtility::matchHeaders(const HeaderMap& request_headers,
   // No headers to match is considered a match.
   if (!config_headers.empty()) {
     for (const HeaderDataPtr& cfg_header_data : config_headers) {
-      if (cfg_header_data->matchesHeaders(request_headers)) {
+      if (!cfg_header_data->matchesHeaders(request_headers)) {
         return false;
       }
     }
"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 156,
    "severity": "critical",
    "description": "When maybeSetupDelay returns true (indicating a delay was injected), the filter now returns Continue instead of StopIteration. This allows the request to continue through the filter chain immediately, bypassing the delay timer. The filter chain should stop iteration while the delay timer is active, then continue when the timer fires via continueDecoding().",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -153,7 +153,7 @@ Http::FilterHeadersStatus FaultFilter::decodeHeaders(Http::RequestHeaderMap& hea
   maybeSetupResponseRateLimit(headers);

   if (maybeSetupDelay(headers)) {
-    return Http::FilterHeadersStatus::Continue;
+    return Http::FilterHeadersStatus::StopIteration;
   }

   if (maybeDoAbort(headers)) {
"
  },
  {
    "file": "source/extensions/filters/http/fault/fault_filter.cc",
    "line": 462,
    "severity": "critical",
    "description": "Inverted logic for managing active fault gauge in postDelayInjection. The code decrements the active fault gauge when isResponseRateLimitConfigured() is TRUE, but should decrement when it's FALSE. According to the comment, the gauge should only be decremented when the delay timer is done AND no other type of fault is active (i.e., no response rate limit configured). With inverted logic, it leaks gauge counts when no rate limit is configured, causing resource tracking errors.",
    "fix_patch": "--- a/source/extensions/filters/http/fault/fault_filter.cc
+++ b/source/extensions/filters/http/fault/fault_filter.cc
@@ -459,7 +459,7 @@ void FaultFilter::postDelayInjection(const Http::RequestHeaderMap& request_heade
     // have been checked earlier, here we just check if there's a response rate limit configured.
     ASSERT(fault_active_);
     ASSERT(delay_timer_ == nullptr);
-    if (isResponseRateLimitConfigured()) {
+    if (!isResponseRateLimitConfigured()) {
       config_->stats().active_faults_.dec();
       fault_active_ = false;
     }
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 503,
    "severity": "high",
    "description": "Route cache clearing code was removed when ext_authz modifies request headers, query parameters, or path. This causes a cross-filter interaction bug: when ext_authz modifies headers/query parameters that affect routing, downstream filters don't see the updated route decision because it's cached from before the modifications. The route cache should be cleared when headers_to_set, headers_to_append, headers_to_remove, or query parameters are modified.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -500,7 +500,15 @@ void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
   switch (response->status) {
   case CheckStatus::OK: {
     // Any changes to request headers or query parameters can affect how the request is going to be
-    // routed. Route cache clearing handled by downstream filters.
+    // routed. If we are changing the headers we also need to clear the route
+    // cache.
+    if (config_->clearRouteCache() &&
+        (!response->headers_to_set.empty() || !response->headers_to_append.empty() ||
+         !response->headers_to_remove.empty() || !response->query_parameters_to_set.empty() ||
+         !response->query_parameters_to_remove.empty())) {
+      ENVOY_STREAM_LOG(debug, "ext_authz is clearing route cache", *decoder_callbacks_);
+      decoder_callbacks_->downstreamCallbacks()->clearRouteCache();
+    }

     ENVOY_STREAM_LOG(trace,
                      "ext_authz filter added header(s) to the request:", *decoder_callbacks_);
"
  },
  {
    "file": "source/extensions/filters/http/ext_authz/ext_authz.cc",
    "line": 592,
    "severity": "high",
    "description": "Removed header removability check using HeaderUtility::isRemovableHeader. This allows ext_authz to remove pseudo-headers (starting with ':') and the Host header when processing headers_to_remove, which would make the request malformed. The code previously checked if a header was removable before attempting removal, now it allows any header to be removed.",
    "fix_patch": "--- a/source/extensions/filters/http/ext_authz/ext_authz.cc
+++ b/source/extensions/filters/http/ext_authz/ext_authz.cc
@@ -589,6 +589,14 @@ void Filter::onComplete(Filters::Common::ExtAuthz::ResponsePtr&& response) {
         ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
         continue;
       }
+      // We don't allow removing any :-prefixed headers, nor Host, as removing them would make the
+      // request malformed. checkDecoderHeaderMutation also performs this check, however, so only
+      // perform this check explicitly if decoder header mutation rules is empty.
+      if (!config_->hasDecoderHeaderMutationRules() &&
+          !Http::HeaderUtility::isRemovableHeader(key)) {
+        ENVOY_STREAM_LOG(trace, "Ignoring invalid header removal '{}'.", *decoder_callbacks_, key);
+        continue;
+      }
       // Header mutation rules handle validation if configured.
       // Check header mutation is valid according to configured decoder header mutation rules.
       Http::LowerCaseString lowercase_key(key);
"
  },
  {
    "file": "source/common/http/filter_manager.cc",
    "line": 1294,
    "severity": "critical",
    "description": "Inverted logic in response header validation check in FilterManager::encodeHeaders. The code now sends a BadGateway error when checkRequiredResponseHeaders returns SUCCESS (status.ok() is true), instead of when it returns FAILURE. This causes all responses with valid headers to be rejected with BadGateway, while responses missing required status headers would pass through. The condition should be negated: if (!status.ok()).",
    "fix_patch": "--- a/source/common/http/filter_manager.cc
+++ b/source/common/http/filter_manager.cc
@@ -1291,7 +1291,7 @@ void FilterManager::encodeHeaders(ActiveStreamEncoderFilter* filter, ResponseHea
   // See the previous attempt (#15658) for detail, and for now we choose to protect only against
   // filter chains.
   const auto status = HeaderUtility::checkRequiredResponseHeaders(headers);
-  if (status.ok()) {
+  if (!status.ok()) {
     // If the check failed, then we reply with BadGateway, and stop the further processing.
     sendLocalReply(
         Http::Code::BadGateway, status.message(), nullptr, absl::nullopt,
"
  }
]

